UserPromptSubmit.command:
repo_root=$(git rev-parse --show-toplevel 2>/dev/null || pwd) && log_dir="$repo_root/.github/logs" && log_file="$log_dir/ai-chat-log.jsonl" && mkdir -p "$log_dir" && payload=$(cat) && ts=$(date '+%Y-%m-%dT%H:%M:%S%z') && printf '{"timestamp":"%s","phase":"before","hook":"UserPromptSubmit","payload":%s}
' "$ts" "$payload" >> "$log_file" && recent=$(tail -n 20 "$log_file" 2>/dev/null | tr '
' '|' | cut -c1-4000 | sed 's/\/\\/g; s/"/\"/g') && printf '{"hookSpecificOutput":{"hookEventName":"UserPromptSubmit","additionalContext":"项目聊天日志(最近20条, | 分隔): %s"}}
' "$recent"
